import React from 'react';
import { render, screen, fireEvent } from '@testing-library/react';
import { {component_name} } from './{component_path}';

describe('{component_name}', () => {
  test('renders correctly', () => {
    render(<{component_name} />);
    expect(screen.getByText('{expected_text}')).toBeInTheDocument();
  });

  test('handles user interaction', () => {
    render(<{component_name} />);
    const button = screen.getByRole('button');
    fireEvent.click(button);
    expect(screen.getByText('{expected_text_after_click}')).toBeInTheDocument();
  });
});

import { renderHook, act } from '@testing-library/react-hooks';
import { {hook_name} } from './{hook_path}';

describe('{hook_name}', () => {
  test('initial state', () => {
    const { result } = renderHook(() => {hook_name}());
    expect(result.current.{state_name}).toBe({initial_value});
  });

  test('updates state', () => {
    const { result } = renderHook(() => {hook_name}());
    act(() => {
      result.current.{setter_name}({new_value});
    });
    expect(result.current.{state_name}).toBe({new_value});
  });
});
